 / $seconds2)) != 0) {			$print .= ($count2 == 1) ? ', 1 '.$name2 : ", $count2 {$name2}s";		}	} elseif ($count == 0) {		// if minutes are zero, show seconds		$print = $since ." second". ($since == 1 ? NULL : "s");			}// elseif ($count == 1) {	//	$print = ", ". ($since - 60) ." second". (($since - 60) == 1 ? NULL : "s");	//}            return $print;	}/**** END FUNCTION ****//*		function clalcs_ XXX() {	}/**** END FUNCTION ****/?>